import asyncio
import websockets
import json
import uuid
from collections import defaultdict

class GameServer:
    def __init__(self):
        self.players = {}  # {websocket: {"player_id": str, "inventory": {item_id: quantity}}}
        self.player_sockets = {} # {player_id: websocket}
        self.items = {
            "sword": {"name": "Sword", "value": 10},
            "shield": {"name": "Shield", "value": 8},
            "potion": {"name": "Potion", "value": 2},
            "gold": {"name": "Gold Coin", "value": 1}
        }
        self.item_ownership = defaultdict(lambda: defaultdict(int)) # {player_id: {item_id: quantity}}
        self.item_locks = defaultdict(asyncio.Lock) # {item_id: asyncio.Lock} to prevent race conditions on item transfers

    async def register(self, websocket):
        player_id = str(uuid.uuid4())
        self.players[websocket] = {"player_id": player_id, "inventory": defaultdict(int)}
        self.player_sockets[player_id] = websocket
        print(f"Player {player_id} connected.")
        # Give initial items for testing
        self.item_ownership[player_id]["gold"] = 100
        self.item_ownership[player_id]["sword"] = 1
        self.item_ownership[player_id]["potion"] = 5
        await self.send_inventory_update(websocket, player_id)
        return player_id

    async def unregister(self, websocket):
        player_data = self.players.pop(websocket, None)
        if player_data:
            player_id = player_data["player_id"]
            self.player_sockets.pop(player_id, None)
            print(f"Player {player_id} disconnected.")

    async def send_message(self, websocket, message_type, payload):
        message = json.dumps({"type": message_type, "payload": payload})
        try:
            await websocket.send(message)
        except websockets.exceptions.ConnectionClosed:
            print(f"Failed to send message to closed connection.")

    async def send_inventory_update(self, websocket, player_id):
        await self.send_message(websocket, "inventory_update", {
            "player_id": player_id,
            "inventory": dict(self.item_ownership[player_id])
        })

    async def get_player_inventory(self, player_id):
        return dict(self.item_ownership[player_id])

    async def transfer_item(self, sender_id, receiver_id, item_id, quantity):
        if quantity <= 0:
            return False, "Quantity must be positive."

        # Acquire locks for both item types involved in the transfer to prevent deadlocks
        # Sort item_ids to ensure consistent lock acquisition order
        locks_to_acquire = [self.item_locks[item_id]]
        
        # This simplified example only locks the specific item being transferred.
        # For more complex scenarios (e.g., trade where multiple item types move),
        # consider locking a "trade" resource or all item types involved.
        # For this example, locking the specific item_id is sufficient for its quantity.

        async with self.item_locks[item_id]:
            # Check if sender has enough of the item
            if self.item_ownership[sender_id][item_id] < quantity:
                return False, f"Sender {sender_id} does not have {quantity} of {item_id}."

            self.item_ownership[sender_id][item_id] -= quantity
            self.item_ownership[receiver_id][item_id] += quantity
            return True, "Item transfer successful."

    async def handle_trade_request(self, websocket, sender_id, payload):
        receiver_id = payload.get("receiver_id")
        item_id = payload.get("item_id")
        quantity = payload.get("quantity")

        if not all([receiver_id, item_id, quantity]):
            await self.send_message(websocket, "error", {"message": "Invalid trade request payload."})
            return

        if receiver_id not in self.player_sockets:
            await self.send_message(websocket, "error", {"message": f"Receiver {receiver_id} not found."})
            return
        
        if item_id not in self.items:
            await self.send_message(websocket, "error", {"message": f"Item {item_id} does not exist."})
            return

        try:
            quantity = int(quantity)
        except ValueError:
            await self.send_message(websocket, "error", {"message": "Quantity must be an integer."})
            return

        success, message = await self.transfer_item(sender_id, receiver_id, item_id, quantity)

        if success:
            await self.send_message(websocket, "trade_success", {"message": message})
            await self.send_inventory_update(websocket, sender_id)

            receiver_socket = self.player_sockets[receiver_id]
            await self.send_message(receiver_socket, "trade_received", {
                "sender_id": sender_id,
                "item_id": item_id,
                "quantity": quantity,
                "message": f"{sender_id} sent you {quantity} {item_id}."
            })
            await self.send_inventory_update(receiver_socket, receiver_id)
            print(f"Trade successful: {sender_id} -> {receiver_id}, {quantity}x {item_id}")
        else:
            await self.send_message(websocket, "error", {"message": f"Trade failed: {message}"})
            print(f"Trade failed: {sender_id} -> {receiver_id}, {quantity}x {item_id} - {message}")

    async def handler(self, websocket, path):
        player_id = await self.register(websocket)
        try:
            async for message in websocket:
                try:
                    data = json.loads(message)
                    message_type = data.get("type")
                    payload = data.get("payload", {})

                    print(f"Received from {player_id}: Type={message_type}, Payload={payload}")

                    if message_type == "request_inventory":
                        await self.send_inventory_update(websocket, player_id)
                    elif message_type == "trade_item":
                        await self.handle_trade_request(websocket, player_id, payload)
                    else:
                        await self.send_message(websocket, "error", {"message": "Unknown message type."})
                except json.JSONDecodeError:
                    await self.send_message(websocket, "error", {"message": "Invalid JSON."})
                except Exception as e:
                    print(f"Error handling message from {player_id}: {e}")
                    await self.send_message(websocket, "error", {"message": f"Server error: {e}"})
        finally:
            await self.unregister(websocket)

async def main():
    server = GameServer()
    async with websockets.serve(server.handler, "localhost", 8765):
        print("Game server started on ws://localhost:8765")
        await asyncio.Future()  # Run forever

if __name__ == "__main__":
    asyncio.run(main())